public boolean isValidSerialization(String preorder) {
    String[] nodes = preorder.split(",");
    int node_count = 1;

    for (String node : nodes) {
        node_count--;

        if (node_count < 0) return false;
        if (!node.equals("#")) node_count += 2;
    }

    return node_count == 0;
}
```

